package com.securestack;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.beans.factory.annotation.Autowired;import java.util.*;import com.securestack.analysis.SecurityRule;import com.securestack.dto.Dto.ScanFileInput;@SpringBootTest class RulesTest{@Autowired List<SecurityRule> rules;@Test void detectsRequiredFindings(){var file=new ScanFileInput("app.js","js","const JWT_SECRET = \"supersecret123\"; app.use(cors({ origin: \"*\" })); Runtime.getRuntime().exec(cmd); block_public_acls = false");var findings=rules.stream().flatMap(r->r.analyze(file).stream()).toList();assertTrue(findings.size()>=4);}}
